1	//! The `grad(expr, wrt)` built-in: reverse-mode autograd over
2	//! a tree-walked mini-evaluator that lifts array-valued operations
3	//! onto an autograd tape.
4	
5	use std::collections::HashMap;
6	use std::rc::Rc;
7	
8	use mlpl_array::{DenseArray, Shape};
9	use mlpl_autograd::{Tape, Tensor};
10	use mlpl_parser::{BinOpKind, Expr};
11	
12	use crate::env::Environment;
13	use crate::error::EvalError;
14	
15	/// Evaluate a `grad(expr, wrt)` call and return the gradient array of
16	/// the scalar expression `expr` with respect to the parameter `wrt`.
17	pub(crate) fn eval_grad(args: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
18	    if args.len() != 2 {
19	        return Err(EvalError::BadArity {
20	            func: "grad".into(),
21	            expected: 2,
22	            got: args.len(),
23	        });
24	    }
25	    let wrt_name = match &args[1] {
26	        Expr::Ident(n, _) => n.clone(),
27	        _ => {
28	            return Err(EvalError::Unsupported(
29	                "grad: second argument must be a parameter identifier".into(),
30	            ));
31	        }
32	    };
33	    if !env.is_param(&wrt_name) {
34	        return Err(EvalError::Unsupported(format!(
35	            "grad: '{wrt_name}' is not a tracked parameter"
36	        )));
37	    }
38	    let tape = Tape::new();
39	    let mut params: HashMap<String, Tensor> = HashMap::new();
40	    for (name, value) in env.params() {
41	        params.insert(name.clone(), Tensor::param(Rc::clone(&tape), value.clone()));
42	    }
43	    let root = eval_tensor_expr(&args[0], env, &tape, &params)?;
44	    root.backward();
45	    let wrt_tensor = params
46	        .get(&wrt_name)
47	        .expect("wrt param present in params map");
48	    Ok(wrt_tensor
49	        .grad()
50	        .unwrap_or_else(|| DenseArray::zeros(wrt_tensor.value().shape().clone())))
51	}
52	
53	fn eval_tensor_expr(
54	    expr: &Expr,
55	    env: &mut Environment,
56	    tape: &Rc<Tape>,
57	    params: &HashMap<String, Tensor>,
58	) -> Result<Tensor, EvalError> {
59	    match expr {
60	        Expr::IntLit(n, _) => Ok(const_leaf(tape, DenseArray::from_scalar(*n as f64))),
61	        Expr::FloatLit(f, _) => Ok(const_leaf(tape, DenseArray::from_scalar(*f))),
62	        Expr::Ident(name, _) => {
63	            if let Some(t) = params.get(name) {
64	                return Ok(t.clone());
65	            }
66	            let arr = env
67	                .get(name)
68	                .cloned()
69	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
70	            Ok(const_leaf(tape, arr))
71	        }
72	        Expr::ArrayLit(_, _) => {
73	            let arr = crate::eval_ops::eval_array_lit(array_lit_elems(expr), env, &mut None)?;
74	            Ok(const_leaf(tape, arr))
75	        }
76	        Expr::UnaryNeg { operand, .. } => Ok(eval_tensor_expr(operand, env, tape, params)?.neg()),
77	        Expr::BinOp { op, lhs, rhs, .. } => {
78	            let l = eval_tensor_expr(lhs, env, tape, params)?;
79	            let r = eval_tensor_expr(rhs, env, tape, params)?;
80	            Ok(match op {
81	                BinOpKind::Add => l.add(&r),
82	                BinOpKind::Sub => l.sub(&r),
83	                BinOpKind::Mul => l.mul(&r),
84	                BinOpKind::Div => l.div(&r),
85	            })
86	        }
87	        Expr::FnCall { name, args, .. } => eval_tensor_fncall(name, args, env, tape, params),
88	        Expr::TensorCtor { shape, .. } => {
89	            let dims = eval_shape_dims(shape, env)?;
90	            Ok(const_leaf(tape, DenseArray::zeros(Shape::new(dims))))
91	        }
92	        Expr::Assign { .. } | Expr::Repeat { .. } | Expr::StrLit(_, _) => Err(
93	            EvalError::Unsupported("grad: expression form not supported inside grad()".into()),
94	        ),
95	    }
96	}
97	
98	fn eval_tensor_fncall(
99	    name: &str,
100	    args: &[Expr],
101	    env: &mut Environment,
102	    tape: &Rc<Tape>,
103	    params: &HashMap<String, Tensor>,
104	) -> Result<Tensor, EvalError> {
105	    if let Some(op) = unary_tensor_op(name) {
106	        check_arity(name, args, 1)?;
107	        let a = eval_tensor_expr(&args[0], env, tape, params)?;
108	        return Ok(op(&a));
109	    }
110	    if name == "matmul" {
111	        check_arity(name, args, 2)?;
112	        let a = eval_tensor_expr(&args[0], env, tape, params)?;
113	        let b = eval_tensor_expr(&args[1], env, tape, params)?;
114	        return Ok(a.matmul(&b));
115	    }
116	    Err(EvalError::Unsupported(format!(
117	        "grad: function '{name}' not supported inside grad()"
118	    )))
119	}
120	
121	fn unary_tensor_op(name: &str) -> Option<fn(&Tensor) -> Tensor> {
122	    Some(match name {
123	        "sum" => Tensor::sum,
124	        "mean" => Tensor::mean,
125	        "exp" => Tensor::exp,
126	        "log" => Tensor::log,
127	        "relu" => Tensor::relu,
128	        "tanh" => Tensor::tanh,
129	        "sigmoid" => Tensor::sigmoid,
130	        "softmax" => Tensor::softmax,
131	        "transpose" => Tensor::transpose,
132	        _ => return None,
133	    })
134	}
135	
136	fn check_arity(name: &str, args: &[Expr], expected: usize) -> Result<(), EvalError> {
137	    if args.len() == expected {
138	        Ok(())
139	    } else {
140	        Err(EvalError::BadArity {
141	            func: name.into(),
142	            expected,
143	            got: args.len(),
144	        })
145	    }
146	}
147	
148	fn const_leaf(tape: &Rc<Tape>, value: DenseArray) -> Tensor {
149	    Tensor::leaf(Rc::clone(tape), value, false)
150	}
151	
152	fn array_lit_elems(expr: &Expr) -> &[Expr] {
153	    match expr {
154	        Expr::ArrayLit(e, _) => e,
155	        _ => unreachable!(),
156	    }
157	}
158	
159	fn eval_shape_dims(shape: &[Expr], env: &mut Environment) -> Result<Vec<usize>, EvalError> {
160	    let mut dims = Vec::with_capacity(shape.len());
161	    for dim_expr in shape {
162	        let arr = crate::eval::eval_expr(dim_expr, env, &mut None)?.into_array()?;
163	        if arr.rank() != 0 {
164	            return Err(EvalError::InvalidShapeDim);
165	        }
166	        let v = arr.data()[0];
167	        if v < 0.0 || v.fract() != 0.0 {
168	            return Err(EvalError::InvalidShapeDim);
169	        }
170	        dims.push(v as usize);
171	    }
172	    Ok(dims)
173	}
174	
[result-id: r5]

