1	//! Reverse-mode backward pass.
2	
3	use mlpl_array::{DenseArray, Shape};
4	
5	use crate::ops::{accumulate, softmax_backward};
6	use crate::tape::{NodeId, NodeKind, Tape};
7	
8	/// Run a backward pass rooted at `root`, seeding `d root / d root = 1`.
9	///
10	/// Walks nodes in reverse topological order (descending node id is
11	/// safe since ops always append after their parents).
12	pub fn backward(tape: &Tape, root: NodeId) {
13	    {
14	        let mut nodes = tape.nodes_mut();
15	        let node = &mut nodes[root.0];
16	        if node.grad.is_none() {
17	            let ones = vec![1.0; node.value.data().len()];
18	            node.grad = Some(DenseArray::new(node.value.shape().clone(), ones).expect("shape"));
19	        }
20	    }
21	    let len = tape.len();
22	    for idx in (0..len).rev() {
23	        propagate(tape, NodeId(idx));
24	    }
25	}
26	
27	fn unbroadcast(grad: DenseArray, target_shape: &Shape) -> DenseArray {
28	    if grad.shape() == target_shape {
29	        return grad;
30	    }
31	    if target_shape.rank() == 0 {
32	        let s: f64 = grad.data().iter().sum();
33	        return DenseArray::from_scalar(s);
34	    }
35	    grad
36	}
37	
38	fn propagate(tape: &Tape, id: NodeId) {
39	    let (kind, upstream) = {
40	        let nodes = tape.nodes();
41	        let node = &nodes[id.0];
42	        let Some(upstream) = node.grad.clone() else {
43	            return;
44	        };
45	        (node.kind.clone(), upstream)
46	    };
47	
48	    match kind {
49	        NodeKind::Leaf => {}
50	        NodeKind::Unary { op, parent } => prop_unary(tape, id, parent, op, &upstream),
51	        NodeKind::Binary { op, left, right } => prop_binary(tape, left, right, op, &upstream),
52	        NodeKind::SumAll { parent } => prop_sum_mean(tape, parent, &upstream, false),
53	        NodeKind::MeanAll { parent } => prop_sum_mean(tape, parent, &upstream, true),
54	        NodeKind::Softmax { parent, axis } => {
55	            let y = tape.nodes()[id.0].value.clone();
56	            let grad = softmax_backward(&y, &upstream, axis);
57	            accumulate(&mut tape.nodes_mut()[parent.0].grad, grad);
58	        }
59	        NodeKind::Transpose { parent } => {
60	            let grad = upstream.transpose();
61	            accumulate(&mut tape.nodes_mut()[parent.0].grad, grad);
62	        }
63	        NodeKind::Reshape { parent, orig_shape } => {
64	            let grad = upstream.reshape(orig_shape).expect("reshape back");
65	            accumulate(&mut tape.nodes_mut()[parent.0].grad, grad);
66	        }
67	        NodeKind::MatMul { left, right } => prop_matmul(tape, left, right, &upstream),
68	    }
69	}
70	
71	fn prop_unary(
72	    tape: &Tape,
73	    id: NodeId,
74	    parent: NodeId,
75	    op: crate::ops::UnaryOp,
76	    upstream: &DenseArray,
77	) {
78	    let x = tape.nodes()[parent.0].value.clone();
79	    let y = tape.nodes()[id.0].value.clone();
80	    let grad_x = op.backward(&x, &y, upstream);
